export const GlobalStatusCoupling = () => (

    {() => {
      const InputWithError = () => {
        const [errorMessage, setErrorMessage] = React.useState(null)
        return (
          <Input
            label="Input"
            placeholder="Write less than 5 chars and dismiss the focus to show the GlobalStatus ..."
            stretch
            status={errorMessage}
            onBlur={({ value }) => {
              setErrorMessage(
